def _build_context_text(results: list[dict]) -> str:
    blocks: list[str] = []
    for item in results:
        if not isinstance(item, dict):
            continue
        content = str(item.get("content", "")).strip()
        if content == "":
            continue
        metadata = item.get("metadata")
        source_url = ""
        if isinstance(metadata, dict):
            source_url = str(metadata.get("source_url", "")).strip()
        if source_url == "":
            blocks.append(content)
        else:
            blocks.append(f"Источник: {source_url}\n{content}")
    return "\n\n---\n\n".join(blocks)


async def run(args, state):
    namespace_id = state.get("rag_namespace_id")
    collection_id = state.get("rag_collection_id")
    question = state.get("content")
    if not isinstance(namespace_id, str) or namespace_id.strip() == "":
        raise ValueError("rag_namespace_id обязателен")
    if not isinstance(collection_id, str) or collection_id.strip() == "":
        raise ValueError("rag_collection_id обязателен")
    if not isinstance(question, str) or question.strip() == "":
        raise ValueError("content обязателен")

    raw = await tools.rag_search(
        namespace_id=namespace_id.strip(),
        collection_id=collection_id.strip(),
        query=question.strip(),
        limit=8,
    )
    if raw.get("success") is not True:
        raise ValueError(str(raw.get("error", "rag_search failed")))
    results = raw.get("results")
    if not isinstance(results, list):
        raise ValueError("RAG search: results должен быть списком")

    state["rag_context"] = results
    state["rag_context_text"] = _build_context_text(results)
    state["need_web_search"] = len(results) == 0
    return state

