async def run(args, state):
    if state.get("need_web_search") is not True:
        return state

    queries = state.get("search_queries")
    if not isinstance(queries, list) or len(queries) == 0:
        raise ValueError("search_queries обязателен")

    per_query_limit = int(state.get("search_links_per_query", 5))
    non_empty = []
    for raw in queries:
        q = str(raw).strip()
        if q != "":
            non_empty.append(q)
    if len(non_empty) == 0:
        raise ValueError("search_queries: нет непустых запросов")

    raw = await tools.browser_duckduckgo_links_batch(
        queries=non_empty,
        per_query_limit=per_query_limit,
    )
    if raw.get("success") is not True:
        raise ValueError(str(raw.get("error", "browser_duckduckgo_links_batch failed")))
    urls = raw.get("urls")
    if not isinstance(urls, list):
        raise ValueError("browser_duckduckgo_links_batch: urls должен быть списком")
    state["search_links"] = urls
    return state
